mapper.update:
update pricing_rule
name = #{name}, min_days_to_expire = #{minDaysToExpire}, max_days_to_expire = #{maxDaysToExpire}, discount_rate = #{discountRate}, priority = #{priority}, status = #{status}, update_time = #{updateTime}, update_user = #{updateUser},
where id = #{id}

mapper.select:
select * from pricing_rule
and name like concat('%', #{name}, '%') and status = #{status}
order by priority desc, id desc
